import numpy as np

def add_self_loops(A):
    return A + np.eye(A.shape[0])

def normalize_adjacency(A_hat):
    d = A_hat.sum(axis=1)
    d_inv_sqrt = np.where(d > 0, 1.0 / np.sqrt(d), 0.0)
    D_inv_sqrt = np.diag(d_inv_sqrt)
    return D_inv_sqrt @ A_hat @ D_inv_sqrt

def gcn_layer_forward(A, H, W, activation=None):
    A_hat = add_self_loops(A)
    A_norm = normalize_adjacency(A_hat)
    Z = A_norm @ H @ W
    if activation == 'relu':
        return np.maximum(0, Z)
    elif activation == 'softmax':
        Z_exp = np.exp(Z - Z.max(axis=1, keepdims=True))
        return Z_exp / Z_exp.sum(axis=1, keepdims=True)
    return Z

def two_layer_gcn(A, X, W1, W2):
    H1 = gcn_layer_forward(A, X, W1, activation='relu')
    H2 = gcn_layer_forward(A, H1, W2, activation='softmax')
    return H2
